using sv_90655e630e164f1f8b36bd62186629ae.Models;

namespace sv_90655e630e164f1f8b36bd62186629ae.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 25),
            new(2, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan, finished with Parmigiano-Reggiano.", 40),
            new(3, "Tiramisu", "Layered espresso-soaked ladyfingers with mascarpone cream and cocoa.", 30),
        },
        [2] = new List<Recipe>
        {
            new(4, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 45),
            new(5, "Guacamole", "Fresh avocado dip with lime, jalapeño, tomato, and cilantro.", 10),
            new(6, "Churros", "Fried dough pastries coated in cinnamon sugar, served with chocolate sauce.", 35),
        },
        [3] = new List<Recipe>
        {
            new(7, "Pad Thai", "Stir-fried rice noodles with shrimp, tofu, peanuts, and tamarind sauce.", 30),
            new(8, "Green Curry", "Aromatic Thai green curry with coconut milk, chicken, and Thai basil.", 35),
            new(9, "Mango Sticky Rice", "Sweet sticky rice topped with ripe mango and coconut cream.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow backend API call.
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@using sv_90655e630e164f1f8b36bd62186629ae.Models
@using sv_90655e630e164f1f8b36bd62186629ae.Services
@using Microsoft.AspNetCore.Components.Routing
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

<nav class="mb-3">
    <a href="/recipes/1" class="btn btn-outline-primary me-1">Italian</a>
    <a href="/recipes/2" class="btn btn-outline-primary me-1">Mexican</a>
    <a href="/recipes/3" class="btn btn-outline-primary me-1">Thai</a>
</nav>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger d-flex align-items-center justify-content-between" role="alert">
        <span>@_errorMessage</span>
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}

@if (_recipes is null && _errorMessage is null)
{
    <div class="d-flex align-items-center gap-2 my-4">
        <div class="spinner-border spinner-border-sm" role="status"></div>
        <span>Loading recipes…</span>
    </div>
}
else if (_recipes is not null)
{
    @if (_isRefreshing)
    {
        <div class="d-flex align-items-center gap-2 mb-3 text-muted small">
            <div class="spinner-border spinner-border-sm" role="status"></div>
            <span>Refreshing…</span>
        </div>
    }

    <div class="row row-cols-1 row-cols-md-3 g-3">
        @foreach (var recipe in _displayedRecipes)
        {
            <div class="col">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                    </div>
                    <div class="card-footer text-muted">
                        Prep time: @recipe.PrepTimeMinutes min
                    </div>
                </div>
            </div>
        }
    </div>

    @if (_displayedRecipes.Count == 0)
    {
        <p class="text-muted">No recipes found for this cuisine.</p>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private List<Recipe> _displayedRecipes = new();
    private bool _isRefreshing;
    private string? _errorMessage;

    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    protected override async Task OnParametersSetAsync()
    {
        // Sort changed but cuisine stayed the same — just re-sort, no reload.
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            ApplySort();
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load for a previous cuisine.
        await CancelPendingLoadAsync();

        _errorMessage = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        var cts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        _loadCts = cts;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Guard against a stale completion after cancellation.
            if (cts.Token.IsCancellationRequested)
                return;

            _recipes = result;
            ApplySort();
            _errorMessage = null;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Expected — the user navigated away or changed cuisine. Do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _errorMessage = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private void ApplySort()
    {
        if (_recipes is null)
            return;

        _displayedRecipes = Sort?.ToLowerInvariant() switch
        {
            "popular" => _recipes.OrderByDescending(r => r.PrepTimeMinutes).ToList(),
            "newest" => _recipes.OrderByDescending(r => r.Id).ToList(),
            _ => _recipes.ToList(),
        };
    }

    private async Task RetryAsync()
    {
        _errorMessage = null;
        await LoadRecipesAsync();
    }

    private async Task CancelPendingLoadAsync()
    {
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

