+    private List<Recipe> _displayedRecipes = new();
+    private bool _isRefreshing;
+    private string? _errorMessage;
+
+    private int _loadedCuisineId;
+    private CancellationTokenSource? _loadCts;
+    private readonly CancellationTokenSource _disposeCts = new();
+
+    protected override async Task OnParametersSetAsync()
+    {
+        // Sort changed but cuisine stayed the same — just re-sort, no reload.
+        if (CuisineId == _loadedCuisineId && _recipes is not null)
+        {
+            ApplySort();
+            return;
+        }
+
+        await LoadRecipesAsync();
+    }
+
+    private async Task LoadRecipesAsync()
+    {
+        // Cancel any in-flight load for a previous cuisine.
+        await CancelPendingLoadAsync();
+
+        _errorMessage = null;
+        _isRefreshing = _recipes is not null;
+        _loadedCuisineId = CuisineId;
+
+        var cts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
+        _loadCts = cts;
+
+        try
+        {
+            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);
+
+            // Guard against a stale completion after cancellation.
+            if (cts.Token.IsCancellationRequested)
+                return;
+
+            _recipes = result;
+            ApplySort();
+            _errorMessage = null;
+        }
+        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
+        {
+            // Expected — the user navigated away or changed cuisine. Do nothing.
+        }
+        catch (TimeoutException ex)
+        {
+            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
+            _errorMessage = "The request timed out. Please try again.";
+        }
+        catch (Exception ex)
+        {
+            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
+            _errorMessage = "Something went wrong loading recipes. Please try again.";
+        }
+        finally
+        {
+            _isRefreshing = false;
+        }
+    }
+
+    private void ApplySort()
+    {
+        if (_recipes is null)
+            return;
+
+        _displayedRecipes = Sort?.ToLowerInvariant() switch
+        {
+            "popular" => _recipes.OrderByDescending(r => r.PrepTimeMinutes).ToList(),
+            "newest" => _recipes.OrderByDescending(r => r.Id).ToList(),
+            _ => _recipes.ToList(),
+        };
+    }
+
+    private async Task RetryAsync()
+    {
+        _errorMessage = null;
+        await LoadRecipesAsync();
+    }
+
+    private async Task CancelPendingLoadAsync()
+    {
+        if (_loadCts is not null)
+        {
+            await _loadCts.CancelAsync();
+            _loadCts.Dispose();
+            _loadCts = null;
+        }
+    }
+
+    public void Dispose()
+    {
+        _disposeCts.Cancel();
+        _disposeCts.Dispose();
+        _loadCts?.Dispose();
+    }
+}
